1	\chapter{The Jacobian as an abelian variety}
2	\label{chap:Jacobian}
3	
4	Let $C$ be a smooth proper curve over $k$ in the sense of Chapter \ref{chap:Genus}, with genus $g = g(C)$.
5	
6	\section{The Picard scheme and the Jacobian}
7	
8	\begin{definition}[Picard functor]
9	  \label{def:Pic_functor}
10	  The \emph{Picard functor} of $C$ over $k$ is the étale sheafification of the presheaf
11	  \[
12	    \underline{\Pic}_{C/k}\colon (\mathrm{Sch}/k)^{\mathrm{op}} \;\to\; \mathrm{Ab},\qquad
13	    S \mapsto \Pic(C \times_k S) / \Pic(S).
14	  \]
15	\end{definition}
16	
17	\begin{theorem}[Representability — Grothendieck FGA, Mumford \emph{Abelian Varieties} §III.13]
18	  \label{thm:Pic_representable}
19	  \uses{def:Pic_functor}
20	  For a smooth proper geometrically connected curve $C$ over $k$, $\underline{\Pic}_{C/k}$ is representable by a smooth, locally finite-type group scheme $\Pic_{C/k}$ over $k$. Its connected component of the identity $\Pic^0_{C/k}$ is a smooth proper geometrically irreducible group scheme over $k$ of dimension $g$, hence an abelian variety.
21	\end{theorem}
22	
23	\begin{definition}[Jacobian]
24	  \label{def:Jacobian}
25	  \lean{AlgebraicGeometry.Jacobian}
26	  \uses{thm:Pic_representable}
27	  The \emph{Jacobian} of $C$ is the abelian variety
28	  \[
29	    \Jac(C) \;=\; \Pic^0_{C/k},
30	  \]
31	  viewed as an object of $\textrm{Over}(\Spec k)$.
32	\end{definition}
33	
34	\section{Group scheme structure and abelian-variety properties}
35	
36	\begin{theorem}[Group object structure]
37	  \label{thm:Jacobian_grpObj}
38	  \lean{AlgebraicGeometry.Jacobian.instGrpObj}
39	  \uses{def:Jacobian}
40	  $\Jac(C)$ carries a canonical group-object structure in $\textrm{Over}(\Spec k)$, induced from tensor product of line bundles on $C$.
41	\end{theorem}
42	
43	\begin{theorem}[Smoothness and dimension]
44	  \label{thm:Jacobian_smooth_genus}
45	  \lean{AlgebraicGeometry.Jacobian.smoothOfRelativeDimension_genus}
46	  \uses{def:Jacobian, def:genus}
47	  $\Jac(C) \to \Spec k$ is smooth of relative dimension $g(C)$.
48	\end{theorem}
49	
50	\begin{theorem}[Properness]
51	  \label{thm:Jacobian_proper}
52	  \lean{AlgebraicGeometry.Jacobian.instIsProper}
53	  \uses{def:Jacobian}
54	  $\Jac(C) \to \Spec k$ is proper.
55	\end{theorem}
56	
57	\begin{theorem}[Geometric irreducibility]
58	  \label{thm:Jacobian_geomIrred}
59	  \lean{AlgebraicGeometry.Jacobian.instGeometricallyIrreducible}
60	  \uses{def:Jacobian}
61	  $\Jac(C) \to \Spec k$ is geometrically irreducible.
62	\end{theorem}
63	
64	\noindent All four properties are part of the conclusion of Theorem \ref{thm:Pic_representable}: once $\Pic^0_{C/k}$ is constructed as an abelian scheme of dimension $g(C)$, smoothness, properness and geometric irreducibility hold by construction.
65	
66	\subsection{Sanity check in low genus}
67	
68	\begin{itemize}
69	  \item $g = 0$: Then $\Pic^0_{C/k} = \Spec k$, the trivial group scheme; $\Jac(\mathbb P^1_k) = \Spec k$ is smooth of relative dimension $0 = g$. The terminal object of $\textrm{Over}(\Spec k)$ already carries \lstinline{GrpObj} via \lstinline{instTensorUnit}.
70	  \item $g = 1$: Then $\Jac(C) \cong C$ once a $k$-rational point on $C$ is fixed; $C$ is itself an abelian variety.
71	  \item $g \ge 2$: $\Jac(C)$ is a non-trivial $g$-dimensional abelian variety, never isomorphic to $C$ as a scheme.
72	\end{itemize}
73	
74	\section{Mathlib gap}
75	
76	The Picard scheme is absent from Mathlib b80f227. Mathlib has only \lstinline{CommRing.Pic R} (the Picard group of a commutative ring) and the abstract \lstinline{GrpObj} machinery. Constructing \lstinline{Jacobian C} therefore requires building, inside this project:
77	
78	\begin{itemize}
79	  \item the Picard functor (Definition \ref{def:Pic_functor}) — needs a global \lstinline{Scheme.Pic} for schemes;
80	  \item étale sheafification of group-valued functors on $\mathrm{Sch}/k$;
81	  \item representability for the curve case (Theorem \ref{thm:Pic_representable});
82	  \item the connected-component-of-identity construction for group schemes locally of finite type.
83	\end{itemize}
84	
85	These are mapped to Phase C of \texttt{STRATEGY.md}.
86	
87	\subsection{Discovery objective for this iteration}
88	
89	The prover should:
90	\begin{enumerate}
91	  \item Verify that no Picard-scheme construction exists in Mathlib (search for \lstinline{Picard}, \lstinline{Pic}, \lstinline{LineBundle}, \lstinline{InvertibleSheaf}, \lstinline{InvertibleModule} inside the algebraic-geometry namespace).
92	  \item For each of the five protected declarations in \lstinline{Jacobian.lean}, document in \lstinline{task_results/Jacobian.md} the smallest helper lemma whose existence in Mathlib would make that declaration provable in $\le 20$ lines.
93	  \item \textbf{Do not} introduce ad-hoc placeholder definitions (e.g. \lstinline{Jacobian C := 𝟙_ (Over (Spec (.of k)))}, which would only satisfy the four instances when $g(C) = 0$ and is therefore mathematically wrong).
94	\end{enumerate}
